const cache = context.get('cache') || new LRUCache.LRUCache({ max: 15000 })
context.set('cache', cache)

if (!msg.projectLink) { // this is the mcp msg
    msg.uuid = crypto.randomBytes(16).toString("hex");
    cache.set(msg.uuid, msg)
    return [msg, null]
} else { // the project link
    const uuid = msg.uuid
    const originalMsg = cache.get(uuid)
    if (originalMsg) {
        originalMsg.payload = msg.payload
        node.send([null, originalMsg], true)
        cache.delete(uuid)
    }
    return null
}

