// Accept input from MCP as msg.payload (object) or msg.payload.args (some clients)
const args = (msg && msg.payload && typeof msg.payload === "object") ? msg.payload : {};
const a = (args && args.args && typeof args.args === "object") ? args.args : args;

const LOCATIONS = {
  "san francisco": { name: "San Francisco, California", latitude: 37.7749, longitude: -122.4194 },
  "reno":          { name: "Reno, Nevada",            latitude: 39.5299, longitude: -119.8143 },
  "chicago":       { name: "Chicago, Illinois",       latitude: 41.8832, longitude: -87.6324 },
  "dallas":        { name: "Dallas, Texas",           latitude: 32.7767, longitude: -96.7970 }
};

function norm(s) {
  return String(s || "").trim().toLowerCase();
}

let locationName = "";
let lat = a.latitude;
let lon = a.longitude;

// Prefer explicit lat/lon if provided
const latNum = Number(lat);
const lonNum = Number(lon);
const hasExplicit = Number.isFinite(latNum) && Number.isFinite(lonNum);

if (hasExplicit) {
  lat = latNum;
  lon = lonNum;
  locationName = a.location ? String(a.location) : "Custom Coordinates";
} else {
  const key = norm(a.location);
  const loc = LOCATIONS[key] || null;
  if (!loc) {
    msg.statusCode = 400;
    msg.payload = {
      error: "Unknown or missing location. Provide location as one of: San Francisco, Reno, Chicago, Dallas; or provide decimal latitude and longitude.",
      received: a.location,
      allowed_locations: Object.values(LOCATIONS).map(x => x.name)
    };
    return msg;
  }
  lat = loc.latitude;
  lon = loc.longitude;
  locationName = loc.name;
}

const temperature_unit = (a.temperature_unit === "fahrenheit") ? "fahrenheit" : "celsius";
const wind_speed_unit = (a.wind_speed_unit === "ms" || a.wind_speed_unit === "mph" || a.wind_speed_unit === "kn") ? a.wind_speed_unit : "kmh";
const precipitation_unit = (a.precipitation_unit === "inch") ? "inch" : "mm";
const timezone = a.timezone ? String(a.timezone) : "auto";

// Current variables are best for "current weather".
// You can add more variables here if you want.
const currentVars = [
  "temperature_2m",
  "relative_humidity_2m",
  "apparent_temperature",
  "precipitation",
  "rain",
  "showers",
  "snowfall",
  "weather_code",
  "wind_speed_10m",
  "wind_direction_10m"
].join(",");

const base = "https://api.open-meteo.com/v1/forecast";
const url = `${base}?latitude=${encodeURIComponent(lat)}&longitude=${encodeURIComponent(lon)}`
  + `&current=${encodeURIComponent(currentVars)}`
  + `&temperature_unit=${encodeURIComponent(temperature_unit)}`
  + `&wind_speed_unit=${encodeURIComponent(wind_speed_unit)}`
  + `&precipitation_unit=${encodeURIComponent(precipitation_unit)}`
  + `&timezone=${encodeURIComponent(timezone)}`;

msg._weather = { location: locationName, latitude: lat, longitude: lon, timezone, temperature_unit, wind_speed_unit, precipitation_unit };
msg.method = "GET";
msg.url = url;
return msg;

const meta = msg._weather || {};

// If the resolver produced an error payload, pass it through
if (msg.statusCode === 400 && msg.payload && msg.payload.error) {
  return msg;
}

const body = msg.payload || {};
const current = body.current || {};

// Open-Meteo returns current_units too
const u = body.current_units || {};

const out = {
  location: meta.location,
  latitude: meta.latitude,
  longitude: meta.longitude,
  timezone: body.timezone || meta.timezone,
  elevation: body.elevation,
  generationtime_ms: body.generationtime_ms,
  current: {
    time: current.time,
    temperature_2m: current.temperature_2m,
    apparent_temperature: current.apparent_temperature,
    relative_humidity_2m: current.relative_humidity_2m,
    precipitation: current.precipitation,
    rain: current.rain,
    showers: current.showers,
    snowfall: current.snowfall,
    wind_speed_10m: current.wind_speed_10m,
    wind_direction_10m: current.wind_direction_10m,
    weather_code: current.weather_code,
    units: {
      temperature_2m: u.temperature_2m,
      apparent_temperature: u.apparent_temperature,
      relative_humidity_2m: u.relative_humidity_2m,
      precipitation: u.precipitation,
      rain: u.rain,
      showers: u.showers,
      snowfall: u.snowfall,
      wind_speed_10m: u.wind_speed_10m,
      wind_direction_10m: u.wind_direction_10m
    }
  },
  summary: null
};

function safe(v) {
  return (v === undefined || v === null) ? "n/a" : v;
}

out.summary = `${out.location} at ${safe(out.current.time)}: `
  + `temp ${safe(out.current.temperature_2m)}${safe(out.current.units.temperature_2m)}, `
  + `feels ${safe(out.current.apparent_temperature)}${safe(out.current.units.apparent_temperature)}, `
  + `humidity ${safe(out.current.relative_humidity_2m)}${safe(out.current.units.relative_humidity_2m)}, `
  + `wind ${safe(out.current.wind_speed_10m)}${safe(out.current.units.wind_speed_10m)} `
  + `@ ${safe(out.current.wind_direction_10m)}${safe(out.current.units.wind_direction_10m)}, `
  + `precip ${safe(out.current.precipitation)}${safe(out.current.units.precipitation)}, `
  + `code ${safe(out.current.weather_code)}.`;

msg.payload = out;
return msg;
